// Build a single state item that drives the IF-node submission loop.
// All loop state lives in the JSON item — this persists correctly across
// Wait node suspension/resume cycles (unlike SplitInBatches context).
//
// Fields:
//   veoRequest      — the Veo API request body (same for every variation)
//   total_count     — how many variations to generate (1-4)
//   current_index   — which variation to submit next (starts at 0)
//   operations      — accumulated submit results []
//   generation_id   — passed through to callbacks
//   user_id         — passed through to callbacks

const body = $('Check Passphrase').first().json.body;

if (!body.first_frame_base64) throw new Error('Missing first_frame_base64 in request body');

const count = Math.min(Math.max(parseInt(body.sample_count) || 2, 1), 4);

const instance = {
  prompt: body.prompt || 'smooth cinematic transition',
  image: {
    bytesBase64Encoded: body.first_frame_base64,
    mimeType: body.first_frame_mime || 'image/jpeg'
  }
};

if (body.last_frame_base64) {
  instance.lastFrame = {
    bytesBase64Encoded: body.last_frame_base64,
    mimeType: body.last_frame_mime || 'image/jpeg'
  };
}

const veoRequest = {
  instances: [instance],
  parameters: {
    aspectRatio:     body.aspect_ratio     || '16:9',
    durationSeconds: parseInt(body.duration_seconds) || 8,
    sampleCount:     1  // locked to 1 on preview tier; fan-out handles multi-variation
  }
};

return [{
  json: {
    veoRequest,
    total_count:   count,
    current_index: 0,
    operations:    [],
    generation_id: body.generation_id,
    user_id:       body.user_id
  }
}];

// Submit the variation at current_index, then increment the index.
// This node is re-entered on every loop iteration via the Wait 31s → More to Submit? path.
// State accumulates in the operations array carried in the JSON item.

// Read API key from environment variable
const API_KEY  = $env.GOOGLE_AI_API_KEY;
const BASE_URL = 'https://generativelanguage.googleapis.com/v1beta';
const MODEL    = 'veo-3.1-generate-preview';

const state = $input.first().json;
const i     = state.current_index;

let operationName = null;
let submitError   = null;

try {
  const resp = await this.helpers.httpRequest({
    method:  'POST',
    url:     `${BASE_URL}/models/${MODEL}:predictLongRunning`,
    headers: {
      'Content-Type':   'application/json',
      'x-goog-api-key': API_KEY
    },
    body: state.veoRequest,
    json: true
  });

  if (resp.name) {
    operationName = resp.name;
  } else {
    submitError = `No operation name in response: ${JSON.stringify(resp).slice(0, 200)}`;
  }
} catch (err) {
  submitError = `Submit failed: ${err.message}`;
}

const newOp = {
  variation_index: i,
  operation_name:  operationName,
  done:  !operationName,   // immediately done (with error) if no name
  uri:   null,
  error: submitError
};

return [{
  json: {
    ...state,
    current_index: i + 1,
    operations:    [...state.operations, newOp]
  }
}];

// Read API key from environment variable
const API_KEY  = $env.GOOGLE_AI_API_KEY;
const BASE_URL = 'https://generativelanguage.googleapis.com/v1beta';

const state      = $input.first().json;
const operations = state.operations.map(op => ({ ...op }));

// Poll all pending ops IN PARALLEL — reduces runner hold time from N×T to T
const pollPromises = operations.map(async (op) => {
  if (op.done || !op.operation_name) return op;

  try {
    const status = await this.helpers.httpRequest({
      method:  'GET',
      url:     `${BASE_URL}/${op.operation_name}`,
      headers: { 'x-goog-api-key': API_KEY },
      json:    true
    });

    if (!status.done) return op;

    const updated = { ...op, done: true };

    const samples =
      status.response?.generateVideoResponse?.generatedSamples ||
      status.response?.generatedSamples ||
      [];

    if (samples.length > 0 && samples[0].video?.uri) {
      const rawUri = samples[0].video.uri;
      updated.uri = rawUri.includes('?') ? rawUri : rawUri + '?alt=media';
    } else if (status.error) {
      updated.error = status.error.message || JSON.stringify(status.error);
    } else {
      updated.error = 'No video URI in completed response';
    }

    return updated;
  } catch (err) {
    return { ...op, done: true, error: `Poll error: ${err.message}` };
  }
});

const updatedOps = await Promise.all(pollPromises);

return [{ json: { ...state, operations: updatedOps } }];

// Build the final videos[] and errors[] arrays from completed operations.

const state = $input.first().json;

const videos = state.operations
  .filter(op => op.uri)
  .sort((a, b) => a.variation_index - b.variation_index)
  .map(op => ({ uri: op.uri, index: op.variation_index }));

const errors = state.operations
  .filter(op => op.error)
  .map(op => ({ index: op.variation_index, error: op.error }));

return [{
  json: {
    videos,
    video_count:   videos.length,
    errors:        errors.length > 0 ? errors : undefined,
    generation_id: state.generation_id,
    user_id:       state.user_id
  }
}];
